content:
{
  "sentences": [
    {
      "text": "師傅什麼時候可以過來修理水龍頭？",
      "pinyin": "Shīfù shénme shíhou kěyǐ guòlái xiūlǐ shuǐlóngtóu?",
      "pinyin_numeric": "shi1fu4 shen2me shi2hou ke3yi3 guo4lai2 xiu1li3 shui3long2tou2",
      "translation_en": "When can the repairman come to fix the faucet?",
      "translation_ko": "수리 기사님은 언제 오셔서 수도꼭지를 고칠 수 있나요?"
    },
    {
      "text": "馬桶壞掉了，什麼時候可以來看看？",
      "pinyin": "Mǎtǒng huài diào le, shénme shíhou kěyǐ lái kànkan?",
      "pinyin_numeric": "ma3tong3 huai4 diao4 le0, shen2me shi2hou ke3yi3 lai2 kan4kan5",
      "translation_en": "The toilet is broken; when can you come take a look?",
      "translation_ko": "변기가 고장 났는데, 언제 와서 확인해 주실 수 있나요?"
    },
    {
      "text": "我什麼時候可以預約師傅來檢查冷氣？",
      "pinyin": "Wǒ shénme shíhou kěyǐ yùyuē shīfù lái jiǎnchá lěngqì?",
      "pinyin_numeric": "wo3 shen2me shi2hou ke3yi3 yu4yue1 shi1fu4 lai2 jian3cha2 leng3qi4",
      "translation_en": "When can I schedule a repairman to check the air conditioner?",
      "translation_ko": "언제 수리 기사님을 예약해서 에어컨 점검을 받을 수 있나요?"
    },
    {
      "text": "熱水器有奇怪的聲音，什麼時候可以過來看看？",
      "pinyin": "Rèshuǐqì yǒu qíguài de shēngyīn, shénme shíhou kěyǐ guòlái kànkan?",
      "pinyin_numeric": "re4shui3qi4 you3 qi2guai4 de5 sheng1yin1, shen2me shi2hou ke3yi3 guo4lai2 kan4kan5",
      "translation_en": "The water heater is making a strange noise; when can you come take a look?",
      "translation_ko": "온수기에서 이상한 소리가 나는데, 언제 와서 확인해 주실 수 있나요?"
    },
    {
      "text": "冰箱壞掉了，什麼時候可以來修理？",
      "pinyin": "Bīngxiāng huài diào le, shénme shíhou kěyǐ lái xiūlǐ?",
      "pinyin_numeric": "bing1xiang1 huai4 diao4 le0, shen2me shi2hou ke3yi3 lai2 xiu1li3",
      "translation_en": "The refrigerator is broken; when can you come fix it?",
      "translation_ko": "냉장고가 고장 났는데, 언제 와서 고칠 수 있나요?"
    },
    {
      "text": "排水堵住了，師傅什麼時候可以過來處理？",
      "pinyin": "Páishuǐ dǔ zhù le, shīfù shénme shíhou kěyǐ guòlái chǔlǐ?",
      "pinyin_numeric": "pai2shui3 du3 zhu4 le0, shi1fu4 shen2me shi2hou ke3yi3 guo4lai2 chu3li3",
      "translation_en": "The drain is clogged; when can the repairman come handle it?",
      "translation_ko": "배수가 막혔는데, 수리 기사님은 언제 오셔서 처리해 주실 수 있나요?"
    },
    {
      "text": "電燈開關壞了，什麼時候可以來換？",
      "pinyin": "Diàndēng kāiguān huài le, shénme shíhou kěyǐ lái huàn?",
      "pinyin_numeric": "dian4deng1 kai1guan1 huai4 le0, shen2me shi2hou ke3yi3 lai2 huan4",
      "translation_en": "The light switch is broken; when can you come replace it?",
      "translation_ko": "전등 스위치가 고장 났는데, 언제 와서 교체할 수 있나요?"
    },
    {
      "text": "門鎖壞掉了，什麼時候可以來修理？",
      "pinyin": "Mén suǒ huài diào le, shénme shíhou kěyǐ lái xiūlǐ?",
      "pinyin_numeric": "men2 suo3 huai4 diao4 le0, shen2me shi2hou ke3yi3 lai2 xiu1li3",
      "translation_en": "The door lock is broken; when can you come fix it?",
      "translation_ko": "문 잠금장치가 고장 났는데, 언제 와서 고칠 수 있나요?"
    },
    {
      "text": "洗衣機有漏水的問題，什麼時候可以過來看看？",
      "pinyin": "Xǐyījī yǒu lòushuǐ de wèntí, shénme shíhou kěyǐ guòlái kànkan?",
      "pinyin_numeric": "xi3yi1ji1 you3 lou4shui3 de5 wen4ti2, shen2me shi2hou ke3yi3 guo4lai2 kan4kan5",
      "translation_en": "The washing machine has a leaking problem; when can you come take a look?",
      "translation_ko": "세탁기에 물이 새는 문제가 있는데, 언제 와서 확인해 주실 수 있나요?"
    },
    {
      "text": "窗戶有裂縫，什麼時候可以來處理？",
      "pinyin": "Chuānghù yǒu lièfèng, shénme shíhou kěyǐ lái chǔlǐ?",
      "pinyin_numeric": "chuang1hu4 you3 lie4feng4, shen2me shi2hou ke3yi3 lai2 chu3li3",
      "translation_en": "The window has a crack; when can you come handle it?",
      "translation_ko": "창문에 금이 갔는데, 언제 와서 처리해 주실 수 있나요?"
    }
  ]
}
